// Extract deal data and company ID
const deal = $input.first().json;
const companyId = deal.associations?.companies?.results?.[0]?.id || null;
const props = deal.properties || {};

return [{ json: {
  dealId: deal.id,
  dealName: props.dealname,
  companyId,
  companyName: props.dealname?.replace('Hiring Signal: ', '') || 'Unknown',
  jobTitle: props.job_title_detected || '',
  numOpenings: props.num_openings || '',
  description: props.description || ''
} }];

// Parse Apollo results and extract candidate contacts
const response = $input.first().json;
const dealData = $('Extract Deal Data').item.json;
const people = response.people || response.contacts || [];

if (!people.length) {
  // No Apollo results — pass to Claude for web search fallback
  return [{ json: {
    ...dealData,
    apolloResults: [],
    apolloFailed: true,
    candidateList: 'No results from Apollo — Claude will search the web'
  } }];
}

const candidates = people.slice(0, 5).map(p => ({
  name: `${p.first_name || ''} ${p.last_name || ''}`.trim(),
  title: p.title || '',
  linkedin: p.linkedin_url || '',
  email: p.email || '',
  seniority: p.seniority || ''
}));

const candidateList = candidates.map((c, i) => 
  `${i+1}. ${c.name} — ${c.title} (${c.seniority}) | LinkedIn: ${c.linkedin} | Email: ${c.email}`
).join('\n');

return [{ json: {
  ...dealData,
  apolloResults: candidates,
  apolloFailed: false,
  candidateList
} }];

