// Parse Claude DM verification
const response = $input.first().json;
const dealData = $('Extract Deal Data').item.json;
let text = '';
if (response.content && Array.isArray(response.content)) {
  text = response.content.filter(b => b.type === 'text').map(b => b.text).join('\n');
}

let dm;
try {
  const cleaned = text.replace(/```json|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  dm = JSON.parse(match ? match[0] : cleaned);
} catch (e) {
  dm = { best_match: { name: 'Unknown', title: 'VP Operations', confidence: 'low', why_this_person: 'Parse error' } };
}

const contact = dm.best_match || {};

return [{ json: {
  ...dealData,
  dm_name: contact.name || 'Unknown',
  dm_title: contact.title || 'Operations Leader',
  dm_linkedin: contact.linkedin_url || '',
  dm_email: contact.email || '',
  dm_confidence: contact.confidence || 'low',
  dm_reasoning: contact.why_this_person || '',
  dm_backup_name: dm.backup?.name || '',
  dm_backup_title: dm.backup?.title || ''
} }];

